     1→/**
     2→ * MMS Infinite Canvas
     3→ *
     4→ * The main canvas component that renders PM schedule data at different zoom levels.
     5→ * Uses deck.gl for strategic view (WebGL) and Konva for tactical/operational views (Canvas 2D).
     6→ *
     7→ * Zoom Level Rendering:
     8→ * - STRATEGIC (0-4): deck.gl WebGL heatmap
     9→ * - TACTICAL_WIDE (4-8): deck.gl WebGL compressed blocks
    10→ * - TACTICAL (8-12): Konva HTML5 Canvas Gantt
    11→ * - OPERATIONAL (12-16): Konva HTML5 Canvas detailed cards
    12→ * - DETAIL (16+): React DOM overlay
    13→ *
    14→ * Based on specs/006-user-interface.md Section 6.3.
    15→ */
    16→
    17→import { useRef } from 'react';
    18→import { Card, NonIdealState, Spinner, Tag, Button, ButtonGroup, OverlayToaster, Intent, Position } from '@blueprintjs/core';
    19→
    20→import { useCanvas, useCanvasData, useFleet, usePm, useUi, useOverlay, loadStrategicData, loadTacticalData, loadTacticalWideData, loadOperationalData, loadDetailData, loadBaselineShadowData } from '../../store';
    21→import type { CanvasSliceState } from '../../store/slices/canvas';
    22→import type { CanvasDataState } from '../../store/slices/canvas';
    23→import type { FleetSliceState } from '../../store/slices/fleet';
    24→import type { PmSliceState } from '../../store/slices/pm';
    25→import type { UiSliceState } from '../../store/slices/ui';
    26→import type { OverlaySliceState } from '../../store/slices/overlay';
    27→import type { ZoomLevel } from '../../store/types';
    28→import { StrategicHeatmapLayer, TacticalWideLayer, TacticalGanttLayer, OperationalDetailLayer, DetailCardOverlay, type HeatmapCell, type PmBlock, type OperationalPmBlock, type DragValidationState, type PmMoveImpact } from './layers';
    29→import { DragConfirmationDialog } from './DragConfirmationDialog';
    30→import {
    31→  quickValidatePmMove,
    32→  createDebouncedValidation,
    33→  getPmMoveImpact,
    34→  commitPmMove,
    35→  createCanvasKeyboardHandler,
    36→  type KeyboardHandlerCallbacks,
    37→  // Accessibility utilities
    38→  initializeAnnouncer,
    39→  announceZoomChange,
    40→  announcePmDeselection,
    41→  prefersReducedMotion,
    42→  onReducedMotionChange,
    43→  FOCUS_RING_STYLES,
    44→} from './utils';
    45→import { KeyboardShortcutsDialog } from '../KeyboardShortcutsDialog';
    46→import { Minimap } from './Minimap';
    47→import { BaselineLegend } from '../overlay';
    48→
    49→// Toaster helper for showing notifications
    50→// Uses the static show method which handles async creation
    51→async function showToast(options: {
    52→  intent: typeof Intent[keyof typeof Intent];
    53→  icon: 'error' | 'tick' | 'warning-sign' | 'info-sign';
    54→  message: string;
    55→  timeout: number;
    56→}): Promise<void> {
    57→  const toaster = await OverlayToaster.createAsync({ position: Position.TOP_RIGHT });
    58→  toaster.show(options);
    59→}
    60→
    61→/** Default canvas dimensions when container size is not available */
    62→const DEFAULT_CANVAS_WIDTH = 1200;
    63→const DEFAULT_CANVAS_HEIGHT = 800;
    64→
    65→// Drag confirmation state interface
    66→interface DragConfirmState {
    67→  isOpen: boolean;
    68→  pmId: string | null;
    69→  pmCode: string;
    70→  trainNumber: string;
    71→  sourceDate: string;
    72→  targetDate: string;
    73→  impact: PmMoveImpact | null;
    74→  isLoadingImpact: boolean;
    75→}
    76→
    77→const initialDragConfirmState: DragConfirmState = {
    78→  isOpen: false,
    79→  pmId: null,
    80→  pmCode: '',
    81→  trainNumber: '',
    82→  sourceDate: '',
    83→  targetDate: '',
    84→  impact: null,
    85→  isLoadingImpact: false,
    86→};
    87→
    88→export function InfiniteCanvas() {
    89→  const { state: canvasStateRaw, actions: canvasActions } = useCanvas();
    90→  const { state: canvasDataStateRaw, actions: canvasDataActions } = useCanvasData();
    91→  const { state: fleetStateRaw, actions: fleetActions } = useFleet();
    92→  const { state: pmStateRaw, actions: pmActions } = usePm();
    93→  const { state: uiStateRaw, actions: uiActions } = useUi();
    94→  const { state: overlayStateRaw, actions: overlayActions } = useOverlay();
    95→
    96→  // Fleet data loading initialization ref
    97→  const fleetLoadInitializedRef = useRef(false);
    98→
    99→  // Initialize fleet data loading (runs once)
   100→  if (!fleetLoadInitializedRef.current && typeof window !== 'undefined') {
   101→    fleetLoadInitializedRef.current = true;
   102→
   103→    // Directly fetch fleet data and update the fleet slice
   104→    const loadFleetData = async () => {
   105→      try {
   106→        // Signal sync started
   107→        uiActions?.startSync?.();
   108→
   109→        const [trainsRes, fleetsRes, depotsRes, routesRes] = await Promise.all([
   110→          fetch('/api/v1/trains?pageSize=500'),
   111→          fetch('/api/v1/fleets'),
   112→          fetch('/api/v1/depots'),
   113→          fetch('/api/v1/routes'),
   114→        ]);
   115→
   116→        if (!trainsRes.ok) throw new Error(`Trains fetch failed: ${trainsRes.status}`);
   117→
   118→        const [trainsData, fleetsData, depotsData, routesData] = await Promise.all([
   119→          trainsRes.json(),
   120→          fleetsRes.ok ? fleetsRes.json() : { data: [] },
   121→          depotsRes.ok ? depotsRes.json() : { data: [] },
   122→          routesRes.ok ? routesRes.json() : { data: [] },
   123→        ]);
   124→
   125→        // Update the fleet slice with loaded data
   126→        if (fleetActions?.setTrains && trainsData.data) {
   127→          fleetActions.setTrains(trainsData.data);
   128→        }
   129→        if (fleetActions?.setFleets && fleetsData.data) {
   130→          fleetActions.setFleets(fleetsData.data);
   131→        }
   132→        if (fleetActions?.setDepots && depotsData.data) {
   133→          fleetActions.setDepots(depotsData.data);
   134→        }
   135→        if (fleetActions?.setRoutes && routesData.data) {
   136→          fleetActions.setRoutes(routesData.data);
