   450→  const handlePmDragStart = (pmId: string, sourceDate: string) => {
   451→    // Find PM in tactical data
   452→    const pm = tacticalData?.pmBlocks.find(p => p.pmId === pmId);
   453→    if (!pm) return;
   454→
   455→    // Store drag info
   456→    draggingPmRef.current = {
   457→      pmId,
   458→      pmCode: pm.pmCode,
   459→      trainId: pm.trainId,
   460→      trainNumber: pm.trainNumber,
   461→      sourceDate,
   462→      constraintStart: pm.constraintStart,
   463→      constraintEnd: pm.constraintEnd,
   464→      isLocked: pm.isLocked,
   465→    };
   466→
   467→    // Initialize drag state in PM slice
   468→    pmActions.startDrag({ pmId, sourceDate });
   469→
   470→    // Set initial validation (quick check)
   471→    const quickResult = quickValidatePmMove({
   472→      pmId,
   473→      currentDate: sourceDate,
   474→      targetDate: sourceDate,
   475→      trainId: pm.trainId,
   476→      constraintStart: pm.constraintStart,
   477→      constraintEnd: pm.constraintEnd,
   478→      isLocked: pm.isLocked,
   479→    });
   480→    dragValidationRef.current = quickResult;
   481→    pmActions.setDragValidation({
   482→      isValid: quickResult.isValid,
   483→      message: quickResult.message,
   484→      violations: quickResult.violations,
   485→    });
   486→  };
   487→
   488→  const handlePmDragMove = (pmId: string, targetDate: string) => {
   489→    const dragInfo = draggingPmRef.current;
   490→    if (!dragInfo || dragInfo.pmId !== pmId) return;
   491→
   492→    // Update target date in PM slice
   493→    pmActions.updateDragTarget(targetDate);
   494→
   495→    // Quick client-side validation
   496→    const quickResult = quickValidatePmMove({
   497→      pmId,
   498→      currentDate: dragInfo.sourceDate,
   499→      targetDate,
   500→      trainId: dragInfo.trainId,
   501→      constraintStart: dragInfo.constraintStart,
   502→      constraintEnd: dragInfo.constraintEnd,
   503→      isLocked: dragInfo.isLocked,
   504→    });
   505→    dragValidationRef.current = quickResult;
   506→    pmActions.setDragValidation({
   507→      isValid: quickResult.isValid,
   508→      message: quickResult.message,
   509→      violations: quickResult.violations,
   510→    });
   511→
   512→    // If quick validation passes, trigger debounced API validation
   513→    if (quickResult.isValid && targetDate !== dragInfo.sourceDate) {
   514→      debouncedValidationRef.current.validate({
   515→        pmId,
   516→        currentDate: dragInfo.sourceDate,
   517→        targetDate,
   518→        trainId: dragInfo.trainId,
   519→      });
   520→    }
   521→  };
   522→
   523→  const handlePmDragEnd = async (pmId: string, targetDate: string) => {
   524→    const dragInfo = draggingPmRef.current;
   525→    if (!dragInfo || dragInfo.pmId !== pmId) {
   526→      // Clear drag state
   527→      pmActions.cancelDrag();
   528→      draggingPmRef.current = null;
   529→      return;
   530→    }
   531→
   532→    // Cancel pending validation
   533→    debouncedValidationRef.current.cancel();
   534→
   535→    // If no change, just cancel
   536→    if (targetDate === dragInfo.sourceDate) {
   537→      pmActions.cancelDrag();
   538→      draggingPmRef.current = null;
   539→      return;
   540→    }
   541→
   542→    // Final quick validation
   543→    const finalValidation = quickValidatePmMove({
   544→      pmId,
   545→      currentDate: dragInfo.sourceDate,
   546→      targetDate,
   547→      trainId: dragInfo.trainId,
   548→      constraintStart: dragInfo.constraintStart,
   549→      constraintEnd: dragInfo.constraintEnd,
   550→      isLocked: dragInfo.isLocked,
   551→    });
   552→
   553→    // If invalid, snap back and show toast
   554→    if (!finalValidation.isValid) {
   555→      pmActions.cancelDrag();
   556→      draggingPmRef.current = null;
   557→      void showToast({
   558→        intent: Intent.DANGER,
   559→        icon: 'error',
   560→        message: finalValidation.message || 'Cannot reschedule: constraint violation',
   561→        timeout: 5000,
   562→      });
   563→      return;
   564→    }
   565→
   566→    // Open confirmation dialog
   567→    dragConfirmRef.current = {
   568→      isOpen: true,
   569→      pmId,
   570→      pmCode: dragInfo.pmCode,
   571→      trainNumber: dragInfo.trainNumber,
   572→      sourceDate: dragInfo.sourceDate,
   573→      targetDate,
   574→      impact: null,
   575→      isLoadingImpact: true,
   576→    };
   577→    // Force re-render by ending drag with commit=false (optimistic update)
   578→    pmActions.endDrag(false);
   579→
   580→    // Load impact assessment
   581→    try {
   582→      const impact = await getPmMoveImpact({
   583→        pmId,
   584→        currentDate: dragInfo.sourceDate,
   585→        targetDate,
   586→        trainId: dragInfo.trainId,
   587→      });
   588→      dragConfirmRef.current = {
   589→        ...dragConfirmRef.current,
   590→        impact,
   591→        isLoadingImpact: false,
   592→      };
   593→    } catch {
   594→      dragConfirmRef.current = {
   595→        ...dragConfirmRef.current,
   596→        isLoadingImpact: false,
   597→      };
   598→    }
