/**
 * Tactical Gantt Layer
 *
 * Konva-based Gantt chart layer for tactical PM scheduling (zoom levels 8-12).
 * Renders PM blocks, constraint walls, train labels, and timeline axis.
 *
 * Features:
 * - PM blocks with status-based colors
 * - Compliance window constraint walls
 * - Train labels on the left
 * - Week/day timeline axis at top
 * - Drag-and-drop PM rescheduling (with constraint validation)
 * - Hover tooltips
 *
 * @see specs/006-user-interface.md Section 6.3.3
 */

import { useRef } from 'react';
import { Stage, Layer, Rect, Text, Line, Group, Arrow } from 'react-konva';
import type { KonvaEventObject } from 'konva/lib/Node';
import type { Stage as StageType } from 'konva/lib/Stage';

import type { PmBlock, ConstraintWall, TacticalCanvasData, DragValidationState, BaselineShadowData } from './types';
import { PM_STATUS_COLORS, CONSTRAINT_COLORS, FLEET_COLORS } from '../../theme/colors';

/** Baseline shadow block colors by status */
const BASELINE_SHADOW_COLORS = {
  UNCHANGED: 'rgba(156, 163, 175, 0.2)', // Gray, nearly invisible
  MOVED: 'rgba(234, 179, 8, 0.3)', // Yellow/amber for moved
  ADDED: 'rgba(34, 197, 94, 0.3)', // Green for added
  REMOVED: 'rgba(239, 68, 68, 0.3)', // Red for removed
};

// =============================================================================
// Constants
// =============================================================================

/** Layout constants for the Gantt chart */
const LAYOUT = {
  HEADER_HEIGHT: 48,
  TRAIN_LABEL_WIDTH: 120,
  ROW_HEIGHT: 40,
  PM_BLOCK_HEIGHT: 28,
  PM_BLOCK_MARGIN: 6,
  DAY_WIDTH: 24,
  WEEK_WIDTH: 24 * 7,
  MIN_PM_WIDTH: 20,
  CONSTRAINT_WALL_WIDTH: 2,
  GRID_LINE_COLOR: '#e2e8f0',
  HEADER_BG: '#f8fafc',
  TRAIN_LABEL_BG: '#ffffff',
  FONT_FAMILY: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
};

/** PM status to color mapping */
function getPmColor(status: string): string {
  switch (status) {
    case 'SCHEDULED':
      return PM_STATUS_COLORS.scheduled;
    case 'IN_PROGRESS':
      return PM_STATUS_COLORS.inProgress;
    case 'COMPLETED':
      return PM_STATUS_COLORS.completed;
    case 'CANCELLED':
      return PM_STATUS_COLORS.cancelled;
    case 'DEFERRED':
      return PM_STATUS_COLORS.deferred;
    default:
      return PM_STATUS_COLORS.scheduled;
  }
}

// =============================================================================
// Types
// =============================================================================

export interface TacticalGanttLayerProps {
  data: TacticalCanvasData | null;
  trainOrder: string[];
  fromDate: Date;
  toDate: Date;
  width: number;
  height: number;
  selectedPmIds: string[];
  /** ID of the PM currently being dragged (if any) */
  draggingPmId?: string | null;
  /** Validation state for the current drag operation */
  dragValidation?: DragValidationState | null;
  /** Baseline shadow data for showing PM positions from baseline */
  baselineShadowData?: BaselineShadowData | null;
  onPmClick?: (pmId: string) => void;
  onPmHover?: (pm: PmBlock | null) => void;
  /** Called when drag starts - includes source date */
  onPmDragStart?: (pmId: string, sourceDate: string) => void;
  /** Called during drag as position changes - for real-time validation */
  onPmDragMove?: (pmId: string, targetDate: string) => void;
  /** Called when drag ends - for final commit/cancel */
  onPmDragEnd?: (pmId: string, newDate: string) => void;
  showConstraintWalls?: boolean;
  showGrid?: boolean;
}

interface DayData {
  date: Date;
  dateStr: string;
  dayOfWeek: number;
  isWeekStart: boolean;
  isToday: boolean;
}

interface WeekData {
  weekStart: Date;
  weekNum: number;
  daysInWeek: number;
}

// =============================================================================
// Pure Utility Functions
// =============================================================================

function getDays(fromDate: Date, toDate: Date): DayData[] {
  const days: DayData[] = [];
  const current = new Date(fromDate);
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  while (current <= toDate) {
    const dayOfWeek = current.getDay();
    days.push({
      date: new Date(current),
      dateStr: current.toISOString().split('T')[0],
      dayOfWeek,
      isWeekStart: dayOfWeek === 0,
      isToday: current.getTime() === today.getTime(),
    });
    current.setDate(current.getDate() + 1);
  }
  return days;
}

function getWeeks(days: DayData[]): WeekData[] {
  const weeks: WeekData[] = [];
  let currentWeek: WeekData | null = null;

  for (const day of days) {
    if (day.isWeekStart || currentWeek === null) {
      if (currentWeek) {
        weeks.push(currentWeek);
      }
      const weekNum = getWeekNumber(day.date);

/**
 * Drag Confirmation Dialog
 *
 * Modal dialog for confirming PM reschedule operations.
 * Shows impact assessment and allows user to confirm or cancel.
 *
 * @see specs/006-user-interface.md Section 6.3.4
 */

import {
  Dialog,
  DialogBody,
  DialogFooter,
  Button,
  Intent,
  Callout,
  Spinner,
  Tag,
  Icon,
} from '@blueprintjs/core';

import type { PmMoveImpact, DragConstraintViolation } from './layers/types';

// =============================================================================
// Types
// =============================================================================

export interface DragConfirmationDialogProps {
  isOpen: boolean;
  pmCode: string;
  trainNumber: string;
  sourceDate: string;
  targetDate: string;
  impact: PmMoveImpact | null;
  violations: DragConstraintViolation[];
  isLoading: boolean;
  onConfirm: () => void;
  onCancel: () => void;
}

// =============================================================================
// Component
// =============================================================================

export function DragConfirmationDialog({
  isOpen,
  pmCode,
  trainNumber,
  sourceDate,
  targetDate,
  impact,
  violations,
  isLoading,
  onConfirm,
  onCancel,
}: DragConfirmationDialogProps) {
  const hasErrors = violations.some(v => v.severity === 'ERROR');
  const hasWarnings = violations.some(v => v.severity === 'WARNING');

  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr);
    return date.toLocaleDateString('en-US', {
      weekday: 'short',
      month: 'short',
      day: 'numeric',
      year: 'numeric',
    });
  };

  const daysDiff = Math.round(
    (new Date(targetDate).getTime() - new Date(sourceDate).getTime()) / (1000 * 60 * 60 * 24)
  );

  return (
    <Dialog
      isOpen={isOpen}
      onClose={onCancel}
      title="Confirm PM Reschedule"
      icon="calendar"
      canEscapeKeyClose={!isLoading}
      canOutsideClickClose={!isLoading}
      data-testid="drag-confirmation-dialog"
    >
      <DialogBody>
        {/* PM Info Header */}
        <div style={{
          display: 'flex',
          alignItems: 'center',
          gap: '12px',
          marginBottom: '16px',
          padding: '12px',
          backgroundColor: 'var(--pt-app-secondary-background-color, #f5f8fa)',
          borderRadius: '6px',
        }}>
          <Icon icon="wrench" size={24} color="var(--pt-icon-color)" />
          <div>
            <div style={{ fontWeight: 600, fontSize: '16px' }}>
              {pmCode}
            </div>
            <div style={{ color: 'var(--pt-text-muted)', fontSize: '13px' }}>
              Train {trainNumber}
            </div>
          </div>
        </div>

        {/* Date Change Summary */}
        <div style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          gap: '16px',
          marginBottom: '20px',
          padding: '16px',
          backgroundColor: 'var(--pt-app-background-color)',
          border: '1px solid var(--pt-divider-black)',
          borderRadius: '6px',
        }}>
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: '11px', color: 'var(--pt-text-muted)', marginBottom: '4px' }}>
              FROM
            </div>
            <div style={{ fontWeight: 600 }}>
              {formatDate(sourceDate)}
            </div>
          </div>

          <div style={{
            display: 'flex',
            alignItems: 'center',
            gap: '8px',
            padding: '8px 12px',
            backgroundColor: daysDiff > 0 ? '#fff3cd' : '#d4edda',
            borderRadius: '4px',
          }}>
            <Icon
              icon={daysDiff > 0 ? 'arrow-right' : 'arrow-left'}
              color={daysDiff > 0 ? '#856404' : '#155724'}
            />
            <span style={{
              fontWeight: 600,
              color: daysDiff > 0 ? '#856404' : '#155724',
            }}>
              {Math.abs(daysDiff)} day{Math.abs(daysDiff) !== 1 ? 's' : ''} {daysDiff > 0 ? 'later' : 'earlier'}
            </span>
          </div>

          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: '11px', color: 'var(--pt-text-muted)', marginBottom: '4px' }}>
              TO
            </div>
            <div style={{ fontWeight: 600 }}>
              {formatDate(targetDate)}
            </div>
          </div>
        </div>

        {/* Violations */}
        {violations.length > 0 && (
          <div style={{ marginBottom: '16px' }}>
            {violations.filter(v => v.severity === 'ERROR').map((violation, i) => (
              <Callout
                key={i}
                intent={Intent.DANGER}
                icon="error"
                style={{ marginBottom: '8px' }}
              >
                <strong>{violation.type.replace(/_/g, ' ')}</strong>
                <div style={{ marginTop: '4px' }}>{violation.message}</div>
              </Callout>
            ))}
            {violations.filter(v => v.severity === 'WARNING').map((violation, i) => (
              <Callout
                key={i}
                intent={Intent.WARNING}
                icon="warning-sign"
                style={{ marginBottom: '8px' }}
              >
                <strong>{violation.type.replace(/_/g, ' ')}</strong>
                <div style={{ marginTop: '4px' }}>{violation.message}</div>
              </Callout>
            ))}
          </div>
        )}

        {/* Impact Assessment */}
        {isLoading ? (
          <div style={{ textAlign: 'center', padding: '24px' }}>
            <Spinner size={24} />
            <div style={{ marginTop: '8px', color: 'var(--pt-text-muted)' }}>
              Calculating impact...
            </div>
          </div>
        ) : impact ? (
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(2, 1fr)',
            gap: '12px',
            marginTop: '16px',
          }}>
            {/* Man-hour Impact */}
            <div style={{
              padding: '12px',
              backgroundColor: 'var(--pt-app-secondary-background-color)',
              borderRadius: '6px',
            }}>
              <div style={{
                fontSize: '11px',
                fontWeight: 600,
                color: 'var(--pt-text-muted)',
                marginBottom: '8px',
              }}>
                MAN-HOUR IMPACT
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '4px' }}>
                <span style={{ fontSize: '12px' }}>Source Week:</span>
                <Tag minimal>
                  {impact.manhourChange.sourceWeek.required}h / {impact.manhourChange.sourceWeek.available}h
                </Tag>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                <span style={{ fontSize: '12px' }}>Target Week:</span>
                <Tag
                  minimal
                  intent={impact.manhourChange.targetWeek.required > impact.manhourChange.targetWeek.available
                    ? Intent.DANGER
                    : Intent.NONE
                  }
                >
                  {impact.manhourChange.targetWeek.required}h / {impact.manhourChange.targetWeek.available}h
                </Tag>
              </div>
            </div>

            {/* Cost Impact */}
            <div style={{
              padding: '12px',
              backgroundColor: 'var(--pt-app-secondary-background-color)',
              borderRadius: '6px',
            }}>
              <div style={{
                fontSize: '11px',
                fontWeight: 600,
                color: 'var(--pt-text-muted)',
                marginBottom: '8px',
              }}>
                COST IMPACT
              </div>
              <div style={{
                fontSize: '18px',
                fontWeight: 600,
                color: impact.costChange > 0 ? '#d9534f' : impact.costChange < 0 ? '#5cb85c' : 'inherit',
              }}>
                {impact.costChange > 0 ? '+' : ''}{impact.costChange.toFixed(2)} HKD
              </div>
            </div>

            {/* Baseline Drift */}
            <div style={{
              padding: '12px',
              backgroundColor: 'var(--pt-app-secondary-background-color)',
              borderRadius: '6px',
            }}>
              <div style={{
                fontSize: '11px',
                fontWeight: 600,
                color: 'var(--pt-text-muted)',
                marginBottom: '8px',
              }}>
                BASELINE DRIFT
              </div>
              <div style={{
                fontSize: '18px',
                fontWeight: 600,
                color: Math.abs(impact.driftFromBaseline) > 7 ? '#d9534f' : 'inherit',
              }}>
                {impact.driftFromBaseline > 0 ? '+' : ''}{impact.driftFromBaseline} days
              </div>
            </div>

            {/* Conflicts */}
            {impact.conflictsCreated.length > 0 && (
              <div style={{
                padding: '12px',
                backgroundColor: '#fff3cd',
                borderRadius: '6px',
              }}>
                <div style={{
                  fontSize: '11px',
                  fontWeight: 600,
                  color: '#856404',
                  marginBottom: '8px',
                }}>
                  CONFLICTS CREATED
                </div>
                {impact.conflictsCreated.map((conflict, i) => (
                  <Tag key={i} intent={Intent.WARNING} minimal style={{ marginRight: '4px', marginBottom: '4px' }}>
                    {conflict}
                  </Tag>
                ))}
              </div>
            )}
          </div>
        ) : null}
      </DialogBody>

      <DialogFooter
        actions={
          <>
            <Button
              onClick={onCancel}
              disabled={isLoading}
            >
              Cancel
            </Button>
            <Button
              intent={hasErrors ? Intent.DANGER : hasWarnings ? Intent.WARNING : Intent.PRIMARY}
              onClick={onConfirm}
              disabled={isLoading || hasErrors}
              icon={hasWarnings ? 'warning-sign' : 'tick'}
            >
              {hasErrors ? 'Cannot Reschedule' : hasWarnings ? 'Reschedule Anyway' : 'Confirm Reschedule'}
            </Button>
          </>
        }
      />
    </Dialog>
  );
}

export default DragConfirmationDialog;

