    42→
    43→let pmSchedulerService: ReturnType<typeof getPMSchedulerService> | null = null;
    44→let manHourService: ReturnType<typeof getManHourLevelingService> | null = null;
    45→
    46→function getService(): ReturnType<typeof getPMSchedulerService> {
    47→  if (!pmSchedulerService) {
    48→    pmSchedulerService = getPMSchedulerService();
    49→  }
    50→  return pmSchedulerService;
    51→}
    52→
    53→function getManHourService(): ReturnType<typeof getManHourLevelingService> {
    54→  if (!manHourService) {
    55→    manHourService = getManHourLevelingService();
    56→  }
    57→  return manHourService;
    58→}
    59→
    60→export const pmScheduleRoutes = new Hono<{ Variables: AppVariables }>();
    61→
    62→/**
    63→ * GET /pm/schedule
    64→ *
    65→ * List PM schedules with filtering and pagination.
    66→ *
    67→ * Query Parameters:
    68→ * - trainId: Filter by train
    69→ * - depotId: Filter by assigned depot
    70→ * - pmTypeId: Filter by PM type
    71→ * - status: Filter by status (SCHEDULED, IN_PROGRESS, COMPLETED, DEFERRED, CANCELLED)
    72→ * - fromDate: Target date from (inclusive)
    73→ * - toDate: Target date to (inclusive)
    74→ * - scenarioId: Get scenario schedule (null/omitted = production)
    75→ */
    76→pmScheduleRoutes.get('/pm/schedule', async (c) => {
    77→  // Parse query filters
    78→  const trainId = c.req.query('trainId');
    79→  const depotId = c.req.query('depotId');
    80→  const pmTypeId = c.req.query('pmTypeId');
    81→  const status = c.req.query('status');
    82→  const fromDate = c.req.query('fromDate');
    83→  const toDate = c.req.query('toDate');
    84→  const scenarioId = c.req.query('scenarioId');
    85→
    86→  // Build filter conditions
    87→  const conditions: SQL<unknown>[] = [];
    88→
    89→  if (trainId && isValidUuid(trainId)) {
    90→    conditions.push(eq(pmSchedule.trainId, trainId));
    91→  }
    92→  if (depotId && isValidUuid(depotId)) {
    93→    conditions.push(eq(pmSchedule.assignedDepotId, depotId));
    94→  }
    95→  if (pmTypeId && isValidUuid(pmTypeId)) {
    96→    conditions.push(eq(pmSchedule.pmTypeId, pmTypeId));
    97→  }
    98→  if (status) {
    99→    const validStatuses = ['SCHEDULED', 'IN_PROGRESS', 'COMPLETED', 'DEFERRED', 'CANCELLED'] as const;
   100→    if (validStatuses.includes(status as typeof validStatuses[number])) {
   101→      conditions.push(eq(pmSchedule.status, status as typeof validStatuses[number]));
   102→    }
   103→  }
   104→  if (fromDate) {
   105→    conditions.push(gte(pmSchedule.targetDate, fromDate));
   106→  }
   107→  if (toDate) {
   108→    conditions.push(lte(pmSchedule.targetDate, toDate));
   109→  }
   110→
   111→  // Handle scenario filter
   112→  if (scenarioId && isValidUuid(scenarioId)) {
   113→    conditions.push(eq(pmSchedule.scenarioId, scenarioId));
   114→  } else {
   115→    // Default to production schedule (scenarioId is NULL)
   116→    conditions.push(isNull(pmSchedule.scenarioId));
   117→  }
   118→
   119→  // Parse pagination
   120→  const pagination = parsePaginationQuery({
   121→    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
   122→    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
   123→    sort: c.req.query('sort'),
   124→  });
   125→
   126→  // Count total items
   127→  const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
   128→  const totalResult = await db
   129→    .select({ count: count() })
   130→    .from(pmSchedule)
   131→    .where(whereClause);
   132→  const totalItems = totalResult[0]?.count ?? 0;
   133→
   134→  // Query with relations
   135→  const schedules = await db.query.pmSchedule.findMany({
   136→    where: whereClause,
   137→    with: {
   138→      train: {
   139→        with: {
   140→          fleet: true,
   141→        },
   142→      },
   143→      pmType: true,
   144→      assignedDepot: true,
   145→      assignedTrack: true,
   146→    },
   147→    orderBy: desc(pmSchedule.targetDate),
   148→    limit: pagination.pageSize,
   149→    offset: pagination.offset,
   150→  });
   151→
   152→  // Map to API response format
   153→  const data = schedules.map((pm) => ({
   154→    id: pm.id,
   155→    train: pm.train
   156→      ? {
   157→          id: pm.train.id,
   158→          trainNumber: pm.train.trainNumber,
   159→          fleetCode: pm.train.fleet?.code ?? null,
   160→        }
   161→      : null,
   162→    pmType: pm.pmType
   163→      ? {
   164→          id: pm.pmType.id,
   165→          code: pm.pmType.pmCode,
   166→          name: pm.pmType.pmName,
   167→          estimatedHours: pm.pmType.estimatedHours,
   168→        }
   169→      : null,
   170→    targetDate: pm.targetDate,
   171→    targetMileageKm: pm.targetMileageKm,
   172→    status: pm.status,
   173→    constraintStart: pm.constraintStart,
   174→    constraintEnd: pm.constraintEnd,
   175→    assignedDepot: pm.assignedDepot
   176→      ? {
   177→          id: pm.assignedDepot.id,
   178→          code: pm.assignedDepot.code,
   179→        }
   180→      : null,
   181→    assignedTrack: pm.assignedTrack
   182→      ? {
   183→          id: pm.assignedTrack.id,
   184→          trackNumber: pm.assignedTrack.trackNumber,
   185→          trackType: pm.assignedTrack.trackType,
   186→        }
   187→      : null,
   188→    assignedHours: pm.assignedHours ? Number(pm.assignedHours) : null,
   189→    isLocked: pm.isLocked ?? false,
   190→    maximoWoId: pm.maximoWoId,
   191→  }));
   192→
   193→  return c.json(
   194→    paginatedSuccess(
   195→      data,
   196→      {
   197→        page: pagination.page,
   198→        pageSize: pagination.pageSize,
   199→        totalItems,
   200→      },
   201→      { durationMs: getRequestDuration(c) }
   202→    )
   203→  );
   204→});
