   536→    pmId: updated.id,
   537→    trainId: pm.trainId,
   538→    trainNumber: pm.train?.trainNumber ?? 'Unknown',
   539→    isLocked: true,
   540→    lockedReason: body.reason,
   541→    lockedBy: {
   542→      userId: user?.id ?? SYSTEM_USER_ID,
   543→      displayName: user?.email ?? 'System',
   544→    },
   545→  });
   546→
   547→  return c.json(
   548→    success({
   549→      id: updated.id,
   550→      isLocked: updated.isLocked,
   551→      lockedReason: updated.lockedReason,
   552→      lockedBy: updated.lockedBy,
   553→      lockedAt: updated.lockedAt,
   554→    })
   555→  );
   556→});
   557→
   558→/**
   559→ * POST /pm/schedule/:id/unlock
   560→ *
   561→ * Unlock a PM to allow optimizer changes.
   562→ */
   563→pmScheduleRoutes.post('/pm/schedule/:id/unlock', async (c) => {
   564→  const requestId = getRequestId(c);
   565→  const pmId = c.req.param('id');
   566→
   567→  if (!isValidUuid(pmId)) {
   568→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   569→  }
   570→
   571→  const service = getService();
   572→  const user = c.get('user');
   573→
   574→  // Get PM with train details for broadcast
   575→  const pm = await service.getPm(pmId);
   576→
   577→  const updated = await service.unlockPm(pmId, user?.id ?? SYSTEM_USER_ID);
   578→
   579→  // Broadcast unlock event to all connected canvas subscribers
   580→  const hub = getWebSocketHub();
   581→  hub.broadcastPmLocked({
   582→    pmId: updated.id,
   583→    trainId: pm.trainId,
   584→    trainNumber: pm.train?.trainNumber ?? 'Unknown',
   585→    isLocked: false,
   586→    lockedBy: {
   587→      userId: user?.id ?? SYSTEM_USER_ID,
   588→      displayName: user?.email ?? 'System',
   589→    },
   590→  });
   591→
   592→  return c.json(
   593→    success({
   594→      id: updated.id,
   595→      isLocked: updated.isLocked,
   596→      lockedReason: updated.lockedReason,
   597→      lockedBy: updated.lockedBy,
   598→      lockedAt: updated.lockedAt,
   599→    })
   600→  );
   601→});
   602→
   603→/**
   604→ * GET /pm/schedule/:id/history
   605→ *
   606→ * Get change history for a PM.
   607→ */
   608→pmScheduleRoutes.get('/pm/schedule/:id/history', async (c) => {
   609→  const requestId = getRequestId(c);
   610→  const pmId = c.req.param('id');
   611→
   612→  if (!isValidUuid(pmId)) {
   613→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   614→  }
