   626→    oldAssignedTrackId: entry.oldAssignedTrackId,
   627→    newAssignedTrackId: entry.newAssignedTrackId,
   628→    changedBy: entry.changedByUser
   629→      ? {
   630→          id: entry.changedByUser.id,
   631→          displayName: entry.changedByUser.displayName,
