   895→    endDate.setDate(targetDate.getDate() + durationDays - 1);
   896→
   897→    // Mock change history (in production, this would come from audit trail)
   898→    type ChangeHistoryChangeType = 'CREATE' | 'MOVE' | 'REASSIGN' | 'LOCK' | 'UNLOCK' | 'STATUS_CHANGE';
   899→    const changeHistory: Array<{
   900→      id: string;
   901→      timestamp: string;
   902→      changeType: ChangeHistoryChangeType;
   903→      userId: string;
   904→      userName: string;
   905→      reason?: string;
   906→    }> = [
   907→      {
   908→        id: `${row.pmId}-create`,
