      {
        id: `${row.pmId}-create`,
        timestamp: row.createdAt?.toISOString() ?? new Date().toISOString(),
        changeType: 'CREATE',
        userId: 'system',
        userName: 'System',
        reason: 'Initial PM scheduling',
      },
    ];

    // Add update entry if updatedAt differs from createdAt
    if (row.updatedAt && row.createdAt && row.updatedAt.getTime() !== row.createdAt.getTime()) {
      changeHistory.push({
        id: `${row.pmId}-update`,
        timestamp: row.updatedAt.toISOString(),
        changeType: 'MOVE',
        userId: 'system',
        userName: 'System',
        reason: 'PM updated',
      });
    }

    // Calculate constraint validation
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const constraintEnd = new Date(row.constraintEnd);
    const daysToDeadline = Math.floor((constraintEnd.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));

    const violations: Array<{
      type: 'HARD' | 'SOFT';
      constraint: string;
      message: string;
      canOverride: boolean;
    }> = [];

    const warnings: Array<{
      type: string;
      message: string;
    }> = [];

    if (daysToDeadline < 0) {
      violations.push({
        type: 'HARD',
        constraint: 'Compliance Window',
        message: `PM is ${Math.abs(daysToDeadline)} days past compliance deadline`,
        canOverride: false,
      });
    } else if (daysToDeadline < 7) {
      warnings.push({
        type: 'COMPLIANCE_WARNING',
        message: `Compliance window closes in ${daysToDeadline} days`,
      });
    }

    return {
      pmId: row.pmId,
      trainId: row.trainId,
      trainNumber: row.trainNumber,
      fleetCode: row.fleetCode,
      pmCode: row.pmCode,
      pmDescription: row.pmName ?? row.pmCode,
      targetDate: row.targetDate,
      endDate: endDate.toISOString().split('T')[0],
      durationDays,
      status: row.status,
      constraintStart: row.constraintStart,
      constraintEnd: row.constraintEnd,
      isLocked: row.isLocked ?? false,
      trackNumber: row.trackNumber,
      depotCode: row.depotCode,
      estimatedHours: row.estimatedHours ? parseFloat(row.estimatedHours) : null,
      assignedShift: row.assignedShift,
      // Material requirements - empty for now, can be populated from inventory integration
      materials: [] as Array<{
        materialId: string;
        materialName: string;
        quantityRequired: number;
        quantityAvailable: number;
        status: 'AVAILABLE' | 'LOW_STOCK' | 'UNAVAILABLE' | 'ARRIVING';
        arrivalDate?: string;
      }>,
      displayColor: row.displayColor ?? '#3B82F6',
      // Detail-specific fields
      changeHistory,
      constraintValidation: {
        isValid: violations.length === 0,
        violations,
        warnings,
      },
      assignedCrew: [] as Array<{
        crewId: string;
        crewName: string;
        role: string;
        shift: string;
      }>,
    };
  });

  return c.json(
    success(
      {
        pmBlocks,
        dateRange: {
          fromDate: fromDateStr,
          toDate: toDateStr,
        },
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * GET /canvas/drift-overlay
 *
 * Get drift overlay data showing train drift severity relative to baseline.
 * Used to highlight trains requiring attention in the canvas.
 *
 * Query Parameters:
 * - baselineId: Baseline to compare against (UUID, optional - defaults to latest published)
 */
canvasRoutes.get('/canvas/drift-overlay', async (c) => {
  const requestId = getRequestId(c);

  const baselineIdParam = c.req.query('baselineId');

  if (baselineIdParam && !isValidUuid(baselineIdParam)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid baseline ID format', requestId),
      400
    );
  }

  let baseline;
  if (baselineIdParam) {
    const result = await db
      .select()
      .from(planBaselines)
      .where(eq(planBaselines.id, baselineIdParam))
      .limit(1);

    if (result.length === 0) {
      return c.json(
        error(ErrorCodes.NOT_FOUND, `Baseline not found: ${baselineIdParam}`, requestId),
        404
      );
    }
    baseline = result[0];
  } else {
    const result = await db
      .select()
      .from(planBaselines)
      .where(eq(planBaselines.status, 'PUBLISHED'))
      .orderBy(desc(planBaselines.publishedAt))
      .limit(1);

    if (result.length === 0) {
      return c.json(
        error(ErrorCodes.NOT_FOUND, 'No published baseline found', requestId),
        404
      );
    }
    baseline = result[0];
  }

  const latestAnalysisResult = await db
    .select({ analysisDate: driftAnalysis.analysisDate })
    .from(driftAnalysis)
    .where(eq(driftAnalysis.baselineId, baseline.id))
    .orderBy(desc(driftAnalysis.analysisDate))
    .limit(1);

  if (latestAnalysisResult.length === 0) {
    return c.json(
      success(
        {
          baselineId: baseline.id,
          baselineName: baseline.name,
          trains: [],
        },
        { timing: { durationMs: getRequestDuration(c) } }
      )
    );
  }

  const latestDate = latestAnalysisResult[0].analysisDate;

  const driftResults = await db
    .select({
      trainId: driftAnalysis.trainId,
      trainNumber: trains.trainNumber,
      baselineProjectedKm: driftAnalysis.baselineProjectedKm,
      actualKm: driftAnalysis.actualKm,
      mileageDriftPct: driftAnalysis.mileageDriftPct,
      avgPmDriftDays: driftAnalysis.avgPmDriftDays,
      maxPmDriftDays: driftAnalysis.maxPmDriftDays,
      requiresReplan: driftAnalysis.requiresReplan,
    })
    .from(driftAnalysis)
    .innerJoin(trains, eq(driftAnalysis.trainId, trains.id))
    .where(
      and(
        eq(driftAnalysis.baselineId, baseline.id),
        eq(driftAnalysis.analysisDate, latestDate)
      )
    )
    .orderBy(trains.trainNumber);

  const thresholds = {
    mileageDriftPct: 5.0,
    scheduleDriftDays: 14,
  };

  const trainDrifts = driftResults.map((drift) => {
    const mileagePct = drift.mileageDriftPct ? parseFloat(drift.mileageDriftPct) : 0;
    const maxPmDays = drift.maxPmDriftDays ?? 0;

    let driftSeverity: 'GREEN' | 'YELLOW' | 'RED';
    if (drift.requiresReplan) {
      driftSeverity = 'RED';
    } else if (
      Math.abs(mileagePct) > thresholds.mileageDriftPct * 0.7 ||
      maxPmDays > thresholds.scheduleDriftDays * 0.7
    ) {
      driftSeverity = 'YELLOW';
    } else {
      driftSeverity = 'GREEN';
    }

    return {
      trainId: drift.trainId,
      trainNumber: drift.trainNumber,
      driftSeverity,
      mileageDriftPct: Math.round(mileagePct * 100) / 100,
      pmDrifts: [],
    };
  });

  return c.json(
    success(
      {
        baselineId: baseline.id,
        baselineName: baseline.name,
        trains: trainDrifts,
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * GET /canvas/baseline-shadow
 *
 * Get baseline shadow overlay data showing PM positions from baseline vs current.
 * Used to render shadow blocks behind current PM positions on the canvas.
 *
 * Query Parameters:
 * - baselineId: Baseline to compare against (UUID, optional - defaults to latest published)
 * - fromDate: Start date for PM blocks (ISO date, optional - defaults to today)
 * - toDate: End date for PM blocks (ISO date, optional - defaults to +12 weeks)
 * - trainIds: Comma-separated train IDs to filter (optional)
 */
canvasRoutes.get('/canvas/baseline-shadow', async (c) => {
  const requestId = getRequestId(c);

  const baselineIdParam = c.req.query('baselineId');
  const fromDateParam = c.req.query('fromDate');
  const toDateParam = c.req.query('toDate');
  const trainIdsParam = c.req.query('trainIds');

  if (baselineIdParam && !isValidUuid(baselineIdParam)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid baseline ID format', requestId),
      400
    );
  }

  const trainIdFilter = trainIdsParam ? trainIdsParam.split(',').map((id) => id.trim()) : [];
  for (const id of trainIdFilter) {
    if (!isValidUuid(id)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, `Invalid train ID format: ${id}`, requestId),
        400
      );
    }
  }

  // Get baseline (specified or latest published)
  let baseline;
  if (baselineIdParam) {
    const result = await db
      .select()
      .from(planBaselines)
      .where(eq(planBaselines.id, baselineIdParam))
      .limit(1);

    if (result.length === 0) {
      return c.json(
        error(ErrorCodes.NOT_FOUND, `Baseline not found: ${baselineIdParam}`, requestId),
        404
      );
    }
    baseline = result[0];
  } else {
    const result = await db
      .select()
      .from(planBaselines)
      .where(eq(planBaselines.status, 'PUBLISHED'))
      .orderBy(desc(planBaselines.publishedAt))
      .limit(1);

    if (result.length === 0) {
      return c.json(
        error(ErrorCodes.NOT_FOUND, 'No published baseline found', requestId),
        404
      );
    }
    baseline = result[0];
  }

  // Calculate date range
  const today = new Date();
  const defaultFromDate = new Date(today);
  const defaultToDate = new Date(today);
  defaultToDate.setDate(defaultToDate.getDate() + 12 * 7); // 12 weeks

  let fromDate: Date;
  let toDate: Date;

  if (fromDateParam) {
    fromDate = new Date(fromDateParam);
    if (isNaN(fromDate.getTime())) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid fromDate format', requestId),
        400
      );
    }
  } else {
    fromDate = defaultFromDate;
  }

  if (toDateParam) {
    toDate = new Date(toDateParam);
    if (isNaN(toDate.getTime())) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid toDate format', requestId),
        400
      );
    }
  } else {
    toDate = defaultToDate;
  }

  const fromDateStr = fromDate.toISOString().split('T')[0];
  const toDateStr = toDate.toISOString().split('T')[0];

  // Import baseline PM schedule table
  const { baselinePmSchedule } = await import('../../lib/db/schema');

  // Query baseline PM schedule
  const baselineConditions = [
    eq(baselinePmSchedule.baselineId, baseline.id),
    gte(baselinePmSchedule.projectedDate, fromDateStr),
    lte(baselinePmSchedule.projectedDate, toDateStr),
  ];

  if (trainIdFilter.length > 0) {
    baselineConditions.push(inArray(baselinePmSchedule.trainId, trainIdFilter));
  }

  const baselinePms = await db
    .select({
      baselinePmId: baselinePmSchedule.id,
      trainId: baselinePmSchedule.trainId,
      trainNumber: trains.trainNumber,
      pmTypeId: baselinePmSchedule.pmTypeId,
      pmCode: pmTypes.pmCode,
      projectedDate: baselinePmSchedule.projectedDate,
      displayColor: pmTypes.displayColor,
    })
    .from(baselinePmSchedule)
    .innerJoin(trains, eq(baselinePmSchedule.trainId, trains.id))
    .innerJoin(pmTypes, eq(baselinePmSchedule.pmTypeId, pmTypes.id))
    .where(and(...baselineConditions))
    .orderBy(baselinePmSchedule.projectedDate);

  // Query current PM schedule for comparison
  const currentConditions = [
    gte(pmSchedule.targetDate, fromDateStr),
    lte(pmSchedule.targetDate, toDateStr),
    isNull(pmSchedule.scenarioId), // Production schedule only
  ];

  if (trainIdFilter.length > 0) {
    currentConditions.push(inArray(pmSchedule.trainId, trainIdFilter));
  }

  const currentPms = await db
    .select({
      pmId: pmSchedule.id,
      trainId: pmSchedule.trainId,
      pmTypeId: pmSchedule.pmTypeId,
      targetDate: pmSchedule.targetDate,
    })
    .from(pmSchedule)
    .where(and(...currentConditions));

  // Build a map of current PM positions by train+pmType+date (or nearest)
  const currentPmMap = new Map<string, { pmId: string; targetDate: string }>();
  for (const pm of currentPms) {
    // Key by train+pmType (we'll find the closest match)
    const key = `${pm.trainId}:${pm.pmTypeId}`;
    const existing = currentPmMap.get(key);
    if (!existing || pm.targetDate < existing.targetDate) {
      // Keep the earliest PM of this type for this train
      currentPmMap.set(key, { pmId: pm.pmId, targetDate: pm.targetDate });
    }
  }

  // Create a set of current PM IDs for "added" detection
  const currentPmKeys = new Set<string>();
  for (const pm of currentPms) {
    currentPmKeys.add(`${pm.trainId}:${pm.pmTypeId}:${pm.targetDate}`);
  }

  // Calculate drift and build response
  type BaselineStatus = 'UNCHANGED' | 'MOVED' | 'ADDED' | 'REMOVED';
  const pmBlocks: Array<{
    pmId: string;
    trainId: string;
    trainNumber: string;
    pmCode: string;
    baselineDate: string;
    currentDate: string | null;
    driftDays: number;
    status: BaselineStatus;
    displayColor: string;
  }> = [];

  // Track baseline PMs
  const baselinePmKeys = new Set<string>();

  for (const bpm of baselinePms) {
    const key = `${bpm.trainId}:${bpm.pmTypeId}`;
    const exactKey = `${bpm.trainId}:${bpm.pmTypeId}:${bpm.projectedDate}`;
    baselinePmKeys.add(exactKey);

    const currentPm = currentPmMap.get(key);
    const baselineDate = new Date(bpm.projectedDate);

    let status: BaselineStatus;
    let currentDate: string | null = null;
    let driftDays = 0;

    if (!currentPm) {
      // PM exists in baseline but not in current schedule (within date range)
      status = 'REMOVED';
    } else if (currentPm.targetDate === bpm.projectedDate) {
      status = 'UNCHANGED';
      currentDate = currentPm.targetDate;
    } else {
      status = 'MOVED';
      currentDate = currentPm.targetDate;
      const currentDateObj = new Date(currentPm.targetDate);
      driftDays = Math.round((currentDateObj.getTime() - baselineDate.getTime()) / (1000 * 60 * 60 * 24));
    }

    pmBlocks.push({
      pmId: bpm.baselinePmId,
      trainId: bpm.trainId,
      trainNumber: bpm.trainNumber,
      pmCode: bpm.pmCode,
      baselineDate: bpm.projectedDate,
      currentDate,
      driftDays,
      status,
      displayColor: bpm.displayColor ?? '#6B7280', // Gray for shadow
    });
  }

  // Find PMs that exist in current but not in baseline (ADDED)
  for (const pm of currentPms) {
    const exactKey = `${pm.trainId}:${pm.pmTypeId}:${pm.targetDate}`;
    if (!baselinePmKeys.has(exactKey)) {
      // Check if there's ANY baseline PM for this train+pmType
      const hasBaseline = baselinePms.some(b => b.trainId === pm.trainId && b.pmTypeId === pm.pmTypeId);
      if (!hasBaseline) {
        // This is a truly added PM
        const train = await db.select({ trainNumber: trains.trainNumber }).from(trains).where(eq(trains.id, pm.trainId)).limit(1);
        const pmType = await db.select({ pmCode: pmTypes.pmCode, displayColor: pmTypes.displayColor }).from(pmTypes).where(eq(pmTypes.id, pm.pmTypeId)).limit(1);

        if (train.length > 0 && pmType.length > 0) {
          pmBlocks.push({
            pmId: pm.pmId,
            trainId: pm.trainId,
            trainNumber: train[0].trainNumber,
            pmCode: pmType[0].pmCode,
            baselineDate: pm.targetDate, // Use current date as reference
            currentDate: pm.targetDate,
            driftDays: 0,
            status: 'ADDED',
            displayColor: pmType[0].displayColor ?? '#10B981', // Green for added
          });
        }
      }
    }
  }

  // Calculate summary statistics
  const summary = {
    totalPms: pmBlocks.length,
    movedPms: pmBlocks.filter(b => b.status === 'MOVED').length,
    addedPms: pmBlocks.filter(b => b.status === 'ADDED').length,
    removedPms: pmBlocks.filter(b => b.status === 'REMOVED').length,
    unchangedPms: pmBlocks.filter(b => b.status === 'UNCHANGED').length,
    avgDriftDays: pmBlocks.length > 0
      ? Math.round(pmBlocks.reduce((sum, b) => sum + Math.abs(b.driftDays), 0) / pmBlocks.length * 10) / 10
      : 0,
  };

  return c.json(
    success(
      {
        baselineId: baseline.id,
        baselineName: baseline.name,
        baselineDate: baseline.baselineDate,
        pmBlocks,
        summary,
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * GET /canvas/bow-wave
 *
 * Get bow-wave analysis data showing maintenance clustering risk.
 * Bow-wave occurs when PM work accumulates in later periods, causing
 * operational overload. This data is derived from strategic planner analysis.
 *
 * Thresholds:
 * - >15 PMs/month = warning (yellow)
 * - >40% fleet in simultaneous maintenance = critical (red)
 * - Second half load > 1.5x first half = bow-wave detected
 *
 * Query Parameters:
 * - fleetId: Filter by fleet (UUID, optional)
 * - planId: Use specific strategic plan (UUID, optional - defaults to latest)
 *
 * @see specs/006-user-interface.md Section 6.5 - BowWaveIndicator
 * @see specs/004-domain-services.md Section 4.6 - Strategic Planner (bow-wave detection)
 */
canvasRoutes.get('/canvas/bow-wave', async (c) => {
  const requestId = getRequestId(c);

  const fleetIdParam = c.req.query('fleetId');
  const planIdParam = c.req.query('planId');

  if (fleetIdParam && !isValidUuid(fleetIdParam)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid fleet ID format', requestId),
      400
    );
  }

  if (planIdParam && !isValidUuid(planIdParam)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid plan ID format', requestId),
      400
    );
  }

  // Calculate quarterly PM loads for the next 10 years
  const currentYear = new Date().getFullYear();
  const horizonYears = 10;
  const endYear = currentYear + horizonYears;

  // Build conditions for PM query
  const pmConditions = [
    gte(pmSchedule.targetDate, `${currentYear}-01-01`),
    lte(pmSchedule.targetDate, `${endYear}-12-31`),
    isNull(pmSchedule.scenarioId),
  ];

  if (fleetIdParam) {
    pmConditions.push(eq(trains.fleetId, fleetIdParam));
  }

  // Query PM counts by quarter
  const quarterlyResults = await db
    .select({
      year: sql<number>`EXTRACT(YEAR FROM ${pmSchedule.targetDate})::integer`.as('year'),
      quarter: sql<number>`EXTRACT(QUARTER FROM ${pmSchedule.targetDate})::integer`.as('quarter'),
      pmCount: sql<number>`COUNT(${pmSchedule.id})::integer`.as('pm_count'),
      totalHours: sql<string>`COALESCE(SUM(${pmSchedule.assignedHours}), 0)`.as('total_hours'),
    })
    .from(pmSchedule)
    .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
    .where(and(...pmConditions))
    .groupBy(
      sql`EXTRACT(YEAR FROM ${pmSchedule.targetDate})`,
      sql`EXTRACT(QUARTER FROM ${pmSchedule.targetDate})`
    )
    .orderBy(
      sql`EXTRACT(YEAR FROM ${pmSchedule.targetDate})`,
      sql`EXTRACT(QUARTER FROM ${pmSchedule.targetDate})`
    );

  // Transform quarterly results
  type BowWaveRiskLevel = 'LOW' | 'MEDIUM' | 'HIGH' | 'CRITICAL';

  const quarterlyLoads = quarterlyResults.map((row) => {
    const hours = parseFloat(row.totalHours) || 0;
    // Estimate capacity utilization (assuming 160 hours/quarter/track average)
    const estimatedCapacity = 640; // 4 tracks * 160 hours
    const utilizationPct = Math.round((hours / estimatedCapacity) * 100);

    return {
      quarter: `${row.year} Q${row.quarter}`,
      year: row.year,
      quarterNum: row.quarter,
      pmCount: row.pmCount,
      totalHours: Math.round(hours * 10) / 10,
      capacityUtilizationPct: Math.min(utilizationPct, 200), // Cap at 200%
    };
  });

  // Calculate first-half vs second-half load distribution
  const midpoint = Math.floor(quarterlyLoads.length / 2);
  const firstHalfLoads = quarterlyLoads.slice(0, midpoint);
  const secondHalfLoads = quarterlyLoads.slice(midpoint);

  const firstHalfTotal = firstHalfLoads.reduce((sum, q) => sum + q.pmCount, 0);
  const secondHalfTotal = secondHalfLoads.reduce((sum, q) => sum + q.pmCount, 0);
  const loadImbalanceRatio = firstHalfTotal > 0 ? secondHalfTotal / firstHalfTotal : 1;

  // Calculate risk score based on imbalance
  // Score = 0 if balanced, increases as second half exceeds first half
  let riskScore = 0;
  if (loadImbalanceRatio > 1) {
    // Risk increases from 0 to 1 as ratio goes from 1 to 2
    riskScore = Math.min(1, (loadImbalanceRatio - 1) / 1);
  }

  // Determine risk level
  let riskLevel: BowWaveRiskLevel;
  if (riskScore < 0.25) {
    riskLevel = 'LOW';
  } else if (riskScore < 0.5) {
    riskLevel = 'MEDIUM';
  } else if (riskScore < 0.75) {
    riskLevel = 'HIGH';
  } else {
    riskLevel = 'CRITICAL';
  }

  // Identify peak periods (quarters with >15 PMs/month equivalent)
  interface BowWavePeakPeriod {
    startQuarter: string;
    endQuarter: string;
    averageLoad: number;
    peakLoad: number;
    riskLevel: BowWaveRiskLevel;
  }

  const peakPeriods: BowWavePeakPeriod[] = [];
  let currentPeak: {
    start: string;
    end: string;
    loads: number[];
    peak: number;
  } | null = null;

  for (const q of quarterlyLoads) {
    const monthlyAvg = q.pmCount / 3;
    const isPeak = monthlyAvg > 15; // >15 PMs/month threshold

    if (isPeak) {
      if (!currentPeak) {
        currentPeak = {
          start: q.quarter,
          end: q.quarter,
          loads: [q.pmCount],
          peak: q.pmCount,
        };
      } else {
        currentPeak.end = q.quarter;
        currentPeak.loads.push(q.pmCount);
        currentPeak.peak = Math.max(currentPeak.peak, q.pmCount);
      }
    } else if (currentPeak) {
      // End of peak period
      const avgLoad = Math.round(currentPeak.loads.reduce((a, b) => a + b, 0) / currentPeak.loads.length);
      const monthlyPeak = Math.round(currentPeak.peak / 3);

      let periodRisk: BowWaveRiskLevel;
      if (monthlyPeak > 40) {
        periodRisk = 'CRITICAL';
      } else if (monthlyPeak > 25) {
        periodRisk = 'HIGH';
      } else if (monthlyPeak > 15) {
        periodRisk = 'MEDIUM';
      } else {
        periodRisk = 'LOW';
      }

      peakPeriods.push({
        startQuarter: currentPeak.start,
        endQuarter: currentPeak.end,
        averageLoad: avgLoad,
        peakLoad: currentPeak.peak,
        riskLevel: periodRisk,
      });

      currentPeak = null;
    }
  }

  // Handle trailing peak period
  if (currentPeak) {
    const avgLoad = Math.round(currentPeak.loads.reduce((a, b) => a + b, 0) / currentPeak.loads.length);
    const monthlyPeak = Math.round(currentPeak.peak / 3);

    let periodRisk: BowWaveRiskLevel;
    if (monthlyPeak > 40) {
      periodRisk = 'CRITICAL';
    } else if (monthlyPeak > 25) {
      periodRisk = 'HIGH';
    } else if (monthlyPeak > 15) {
      periodRisk = 'MEDIUM';
    } else {
      periodRisk = 'LOW';
    }

    peakPeriods.push({
      startQuarter: currentPeak.start,
      endQuarter: currentPeak.end,
      averageLoad: avgLoad,
      peakLoad: currentPeak.peak,
      riskLevel: periodRisk,
    });
  }

  // Generate recommendations based on analysis
  type RecommendationType = 'ADVANCE_PM' | 'DEFER_PM' | 'ADD_CAPACITY' | 'SPREAD_WORKLOAD';
  type RecommendationPriority = 'HIGH' | 'MEDIUM' | 'LOW';

  interface BowWaveRecommendation {
    type: RecommendationType;
    description: string;
    impact: string;
    priority: RecommendationPriority;
  }

  const recommendations: BowWaveRecommendation[] = [];

  if (riskLevel === 'CRITICAL' || riskLevel === 'HIGH') {
    recommendations.push({
      type: 'SPREAD_WORKLOAD',
      description: 'Redistribute PM load from second half to first half of planning horizon',
      impact: `Could reduce imbalance ratio from ${loadImbalanceRatio.toFixed(2)}x to ~1.2x`,
      priority: 'HIGH',
    });
  }

  if (peakPeriods.some(p => p.riskLevel === 'CRITICAL')) {
    recommendations.push({
      type: 'ADVANCE_PM',
      description: 'Advance non-critical PMs from peak periods to earlier quarters',
      impact: 'Reduces peak load and prevents operational bottlenecks',
      priority: 'HIGH',
    });
  }

  if (peakPeriods.length > 2) {
    recommendations.push({
      type: 'ADD_CAPACITY',
      description: 'Consider contractor support during peak periods',
      impact: 'Increases throughput by 20-30% during critical periods',
      priority: 'MEDIUM',
    });
  }

  if (riskLevel === 'MEDIUM') {
    recommendations.push({
      type: 'DEFER_PM',
      description: 'Review PMs that can be safely deferred within compliance windows',
      impact: 'Smooths workload distribution across quarters',
      priority: 'LOW',
    });
  }

  // Get affected fleets
  const fleetConditions = fleetIdParam
    ? [eq(fleets.id, fleetIdParam)]
    : [];

  const affectedFleetsResult = await db
    .select({ code: fleets.code })
    .from(fleets)
    .where(fleetConditions.length > 0 ? and(...fleetConditions) : undefined)
    .orderBy(fleets.code);

  const affectedFleets = affectedFleetsResult.map((f) => f.code);

  // Build response
  const bowWaveData = {
    riskLevel,
    riskScore: Math.round(riskScore * 100) / 100,
    planId: planIdParam ?? null,
    planDate: new Date().toISOString().split('T')[0],
    quarterlyLoads,
    peakPeriods,
    recommendations,
    summary: {
      totalPms: firstHalfTotal + secondHalfTotal,
      firstHalfLoad: firstHalfTotal,
      secondHalfLoad: secondHalfTotal,
      loadImbalanceRatio: Math.round(loadImbalanceRatio * 100) / 100,
      affectedFleets,
    },
  };

  return c.json(
    success(bowWaveData, { timing: { durationMs: getRequestDuration(c) } })
  );
});

